{"content": "import { Header } from "@/components/header"
import { Footer } from "@/components/footer"
import { WhatsAppFloat } from "@/components/whatsapp-float"
import content from "@/content/en.json"
import Link from "next/link"

const c = content as any
const h = c.home || {}
const hero = h.hero || {}
const testimonials = h.testimonials || {}
const programs = h.programs || {}
const whyCountry = h.whyCountry || {}
const process = h.process || {}

export default function Home() {
  return (
    <>
      <Header />

      {/* Hero */}
      <section className="relative flex min-h-[80vh] items-center justify-center overflow-hidden">
        <div className="absolute inset-0 bg-gradient-to-br from-primary via-[#1B2A4A] to-[#0F1A30]" />
        <div className="relative z-10 mx-auto max-w-5xl px-4 text-center py-20">
          <h1 className="mb-6 text-4xl font-bold tracking-tight text-white sm:text-5xl lg:text-6xl">{hero.headline}</h1>
          <p className="mx-auto mb-10 max-w-3xl text-lg text-white/80">{hero.subheadline}</p>
          <div className="flex flex-col items-center gap-4 sm:flex-row sm:justify-center">
            <Link href="/programs" className="inline-flex h-12 items-center justify-center rounded-lg bg-secondary px-10 text-base font-semibold text-secondary-foreground transition-all hover:bg-secondary/90">{hero.ctaPrimaryText}</Link>
            <a href={hero.ctaSecondaryHref || "https://calendly.com/nexaparaguay/consulta"} target="_blank" rel="noopener noreferrer" className="inline-flex h-12 items-center justify-center rounded-lg border-2 border-white/50 px-10 text-base font-semibold text-white transition-all hover:bg-white/10">{hero.ctaSecondaryText}</a>
          </div>
        </div>
      </section>

      {/* Trust signals */}
      {h.trust?.items?.length > 0 && (
        <section className="bg-surface-light py-8 border-b border-border">
          <div className="mx-auto max-w-7xl px-4">
            <div className="grid gap-6 sm:grid-cols-2 lg:grid-cols-4">
              {(h.trust.items || []).map((item: any, i: number) => (
                <div key={i} className="flex items-center gap-3">
                  <div className="flex h-10 w-10 items-center justify-center rounded-full bg-primary/10 text-primary text-lg font-bold">{item.icon || i + 1}</div>
                  <div>
                    <p className="font-semibold text-foreground text-sm">{item.title}</p>
                    <p className="text-xs text-muted-foreground">{item.description}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </section>
      )}

      {/* Programs */}
      {programs.items?.length > 0 && (
        <section id="programs" className="bg-background py-20">
          <div className="mx-auto max-w-7xl px-4">
            <h2 className="mb-4 text-center text-3xl font-bold text-foreground">{programs.title}</h2>
            <p className="mb-12 text-center text-muted-foreground max-w-2xl mx-auto">{programs.subtitle}</p>
            <div className="grid gap-8 lg:grid-cols-2 xl:grid-cols-4">
              {(programs.items || []).map((prog: any, i: number) => (
                <div key={i} className="group overflow-hidden rounded-xl border border-border bg-surface shadow-sm transition-all hover:-translate-y-1 hover:shadow-lg">
                  <div className="aspect-[4/3] bg-gradient-to-br from-primary/10 to-accent/10 flex items-center justify-center overflow-hidden">
                    {prog.image && <img src={prog.image} alt={prog.title} className="h-full w-full object-cover" />}
                    {!prog.image && <span className="text-3xl font-bold text-primary/30">{prog.title?.[0]}</span>}
                  </div>
                  <div className="p-6">
                    <h3 className="mb-2 text-lg font-bold text-foreground">{prog.title}</h3>
                    <p className="mb-4 text-sm text-muted-foreground line-clamp-3">{prog.description}</p>
                    {prog.price && <p className="mb-4 text-sm font-bold text-primary">{prog.price}</p>}
                    <ul className="mb-6 flex flex-col gap-1.5 text-sm">
                      {(prog.includes || prog.features || []).slice(0, 5).map((inc: string, j: number) => (
                        <li key={j} className="flex items-start gap-2 text-muted-foreground">
                          <svg className="mt-0.5 h-4 w-4 shrink-0 text-secondary" xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="[REDACTED_PHONE]" fill="none" stroke="currentColor" strokeWidth="2"><path d="M[REDACTED_PHONE]l-5-5"/></svg>
                          {inc}
                        </li>
                      ))}
                    </ul>
                    {prog.ctaHref && <a href={prog.ctaHref} target="_blank" rel="noopener noreferrer"
                      className="inline-flex w-full items-center justify-center rounded-lg bg-primary px-4 py-2.5 text-sm font-semibold text-primary-foreground transition-all hover:bg-primary/90">
                      {prog.ctaText || "Learn More"}
                    </a>}
                  </div>
                </div>
              ))}
            </div>
          </div>
        </section>
      )}

      {/* Why Paraguay */}
      {whyCountry.items?.length > 0 && (
        <section id="why-paraguay" className="bg-surface-light py-20">
          <div className="mx-auto max-w-7xl px-4">
            <h2 className="mb-4 text-center text-3xl font-bold text-foreground">{whyCountry.title}</h2>
            <p className="mb-12 text-center text-muted-foreground max-w-2xl mx-auto">{whyCountry.subtitle}</p>
            <div className="grid gap-8 sm:grid-cols-2 lg:grid-cols-3">
              {(whyCountry.items || []).slice(0, 6).map((item: any, i: number) => (
                <div key={i} className="overflow-hidden rounded-xl border border-border bg-white shadow-sm transition-all hover:-translate-y-1 hover:shadow-md">
                  <div className="aspect-video bg-muted overflow-hidden">
                    {item.image && <img src={item.image} alt={item.title} className="h-full w-full object-cover" />}
                  </div>
                  <div className="p-5">
                    <h3 className="mb-2 font-bold text-foreground">{item.title}</h3>
                    <p className="text-sm text-muted-foreground">{item.description}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </section>
      )}

      {/* Process */}
      {process.steps?.length > 0 && (
        <section id="process" className="bg-background py-20">
          <div className="mx-auto max-w-4xl px-4">
            <h2 className="mb-4 text-center text-3xl font-bold text-foreground">{process.title}</h2>
            <p className="mb-16 text-center text-muted-foreground">{process.subtitle}</p>
            <div className="relative">
              <div className="absolute left-6 top-0 h-full w-0.5 bg-primary/20 md:left-1/2 md:-translate-x-px" />
              <div className="flex flex-col gap-12">
                {(process.steps || []).map((step: any, i: number) => (
                  <div key={i} className={`relative flex flex-col gap-4 md:flex-row ${i % 2 === 0 ? "" : "md:flex-row-reverse"}`}>
                    <div className="flex-1" />
                    <div className="absolute left-4 top-2 z-10 flex h-10 w-10 items-center justify-center rounded-full bg-secondary text-sm font-bold text-secondary-foreground shadow-md md:left-1/2 md:-translate-x-1/2">
                      {step.number || i + 1}
                    </div>
                    <div className={`flex-1 pl-16 md:pl-0 ${i % 2 === 0 ? "md:pr-12 md:text-right" : "md:pl-12"}`}>
                      <div className="rounded-xl border border-border bg-surface p-6 shadow-sm">
                        <h3 className="mb-2 font-bold text-foreground">{step.title}</h3>
                        {step.image && <img src={step.image} alt={step.title} className="mb-3 w-full rounded-lg" />}
                        <p className="text-sm text-muted-foreground">{step.description}</p>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </section>
      )}

      {/* Testimonials */}
      {testimonials.items?.length > 0 && (
        <section id="testimonials" className="bg-surface-light py-20">
          <div className="mx-auto max-w-7xl px-4">
            <h2 className="mb-4 text-center text-3xl font-bold text-foreground">{testimonials.title}</h2>
            <p className="mb-12 text-center text-muted-foreground">{testimonials.subtitle}</p>
            <div className="grid gap-6 sm:grid-cols-2 lg:grid-cols-3">
              {(testimonials.items || []).slice(0, 6).map((t: any, i: number) => (
                <div key={i} className="rounded-xl border border-border bg-white p-6 shadow-sm">
                  <div className="mb-3 flex gap-1 text-secondary">
                    {Array.from({ length: t.rating || 5 }).map((_, j) => <span key={j}>★</span>)}
                  </div>
                  <p className="mb-4 text-sm text-muted-foreground italic">"{t.quote}"</p>
                  <div className="flex items-center gap-3">
                    {t.image && <img src={t.image} alt={t.name} className="h-10 w-10 rounded-full object-cover" />}
                    <div>
                      <p className="font-semibold text-foreground text-sm">{t.name}</p>
                      <p className="text-xs text-muted-foreground">{t.role}</p>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </section>
      )}

      {/* Final CTA */}
      {h.finalCta && (
        <section className="relative overflow-hidden py-20" style={{ background: "linear-gradient(135deg, var(--color-primary) 0%, #0F1A30 100%)" }}>
          <div className="relative z-10 mx-auto max-w-3xl px-4 text-center">
            <h2 className="mb-4 text-3xl font-bold text-white">{h.finalCta.title}</h2>
            <p className="mb-8 text-white/80">{h.finalCta.description}</p>
            <a href={h.finalCta.buttonLink || "https://calendly.com/nexaparaguay/consulta"} target="_blank" rel="noopener noreferrer"
              className="inline-block rounded-lg bg-secondary px-10 py-4 text-base font-semibold text-secondary-foreground transition-all hover:scale-105 hover:bg-secondary/90">
              {h.finalCta.buttonText}
            </a>
          </div>
        </section>
      )}

      <Footer />
      <WhatsAppFloat />
    </>
  )
}
